if (cmd === 'trace') {
  const imageIdx = argv.indexOf('--image');
  const imagePath = imageIdx !== -1 ? argv[imageIdx + 1] : null;
  if (!imagePath) {
    console.error('trace: --image <path> is required');
    process.exit(1);
  }
  const briefIdx = argv.indexOf('--brief');
  const briefPath = briefIdx !== -1 ? argv[briefIdx + 1] : null;
  const archetypeIdx = argv.indexOf('--archetype-hint');
  const archetypeHint = archetypeIdx !== -1 ? argv[archetypeIdx + 1] : null;
  const outIdx = argv.indexOf('-o');
  const outPath = outIdx !== -1 ? argv[outIdx + 1] : null;

  const formData = new FormData();
  const imageBytes = await fs.readFile(imagePath);
  formData.append('image', new Blob([imageBytes]), path.basename(imagePath));
  if (briefPath) {
    const briefBytes = await fs.readFile(briefPath);
    formData.append('brief', new Blob([briefBytes]), path.basename(briefPath));
  }

  const url = archetypeHint
    ? `${base}/api/v3/trace?archetypeHint=${encodeURIComponent(archetypeHint)}`
    : `${base}/api/v3/trace`;

  const res = await fetch(url, { method: 'POST', body: formData });
  const text = await res.text();
  let json;
  try { json = JSON.parse(text); } catch { json = { raw: text }; }

  if (res.ok && json.jobId) {
    console.error(`Trace enqueued as job: ${json.jobId}`);
    console.log(JSON.stringify(json, null, 2));
    return;
  }

  if (!res.ok) {
    console.error(JSON.stringify({ status: res.status, body: json }, null, 2));
    const hasNoWalls = json?.detail?.reason === 'no_walls_detected';
    process.exit(hasNoWalls ? 1 : 1);
  }

  const output = JSON.stringify(json, null, 2);
  if (outPath) {
    await fs.writeFile(outPath, output, 'utf8');
    console.error(`Layout written to ${outPath}`);
  } else {
    console.log(output);
  }

  const advisories = json.advisories ?? [];
  const hasFatal = advisories.some((a) => a.code === 'no_walls_detected');
  process.exit(hasFatal ? 1 : 0);
}

if (cmd === 'jobs') {
